ommit} # timeout=10 Checking out Revision b83d505b09d779238b90ff841aa3c952148782e5 (origin/main) > git config core.sparsecheckout # timeout=10 > git checkout -f b83d505b09d779238b90ff841aa3c952148782e5 # timeout=10 Commit message: "Update deploy.playbook" > git rev-list --no-walk b83d505b09d779238b90ff841aa3c952148782e5 # timeout=10 [Pipeline] } [Pipeline] // script [Pipeline] } [Pipeline] // stage [Pipeline] stage [Pipeline] { (Parse Deploy JSON and Set Env Vars) [Pipeline] script [Pipeline] { [Pipeline] echo Set environment variable: 193_16_16_9-bitra-centos8=193.16.16.9-bitra-centos8 [Pipeline] } [Pipeline] // script [Pipeline] } [Pipeline] // stage [Pipeline] stage [Pipeline] { (Retrive secrets from vault) [Pipeline] script [Pipeline] { [Pipeline] sh + vault login -method=userpass username=hemanth password=bitra Success! You are now authenticated. The token information displayed below is already stored in the token helper. You do NOT need to run "vault login" again. Future Vault requests will automatically use this token.
